"use client";

import { AnimatedShaderHero } from "@/components/animated-shader-hero";

export default function Home() {
  return (
    <main className="relative w-full h-screen overflow-hidden">
      {/* Animated shader background */}
      <AnimatedShaderHero />

      {/* Content overlay */}
      <div className="relative z-10 flex flex-col items-center justify-center h-full text-center">
        <div className="space-y-6">
          <h1 className="text-6xl md:text-7xl font-bold text-white drop-shadow-lg">
            Portfolio
          </h1>
          <p className="text-xl md:text-2xl text-gray-200 drop-shadow-lg">
            Coming Soon
          </p>
          <div className="flex justify-center gap-4">
            <a
              href="https://github.com"
              className="px-6 py-3 bg-white text-black rounded-lg font-semibold hover:bg-gray-200 transition-colors drop-shadow-lg"
            >
              GitHub
            </a>
            <a
              href="https://twitter.com"
              className="px-6 py-3 border-2 border-white text-white rounded-lg font-semibold hover:bg-white hover:text-black transition-colors drop-shadow-lg"
            >
              Twitter
            </a>
          </div>
        </div>
      </div>
    </main>
  );
}
