"use client";

import { useEffect, useRef } from "react";

export function AnimatedShaderHero() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const glRef = useRef<WebGLRenderingContext | null>(null);
  const programRef = useRef<WebGLProgram | null>(null);
  const timeRef = useRef(0);
  const animationIdRef = useRef<number | undefined>(undefined);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Get WebGL context
    const gl = canvas.getContext("webgl");
    if (!gl) {
      console.error("WebGL not supported");
      return;
    }
    glRef.current = gl;

    // Set canvas size
    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      gl.viewport(0, 0, canvas.width, canvas.height);
    };
    resizeCanvas();
    window.addEventListener("resize", resizeCanvas);

    // Vertex shader
    const vertexShader = gl.createShader(gl.VERTEX_SHADER);
    if (!vertexShader) return;
    gl.shaderSource(
      vertexShader,
      `
      precision highp float;
      attribute vec2 position;
      
      void main() {
        gl_Position = vec4(position, 0.0, 1.0);
      }
    `
    );
    gl.compileShader(vertexShader);

    // Fragment shader
    const fragmentShader = gl.createShader(gl.FRAGMENT_SHADER);
    if (!fragmentShader) return;
    gl.shaderSource(
      fragmentShader,
      `
      precision highp float;
      uniform float time;
      uniform vec2 resolution;
      
      vec3 palette(float t) {
        vec3 a = vec3(0.5, 0.5, 0.5);
        vec3 b = vec3(0.5, 0.5, 0.5);
        vec3 c = vec3(1.0, 1.0, 1.0);
        vec3 d = vec3(0.3, 0.2, 0.2);
        
        return a + b * cos(6.28318 * (c * t + d));
      }
      
      float noise(vec3 p) {
        return sin(p.x * 12.9898 + p.y * 78.233 + p.z * 45.164) * 43758.5453;
      }
      
      void main() {
        vec2 uv = gl_FragCoord.xy / resolution.xy;
        uv = (uv - 0.5) * 2.0;
        uv.x *= resolution.x / resolution.y;
        
        float t = time * 0.5;
        float d = length(uv);
        float a = atan(uv.y, uv.x);
        
        // Create animated patterns
        float waves = sin(d * 5.0 - t) * 0.5 + 0.5;
        float rings = sin(d * 20.0 + t * 2.0) * 0.5 + 0.5;
        float spiral = sin(a * 5.0 + d * 10.0 - t * 2.0) * 0.5 + 0.5;
        
        vec3 color = palette(d * 0.5 + t + spiral * 0.3);
        color *= waves * rings;
        color += palette(a + t) * 0.2;
        
        gl_FragColor = vec4(color, 1.0);
      }
    `
    );
    gl.compileShader(fragmentShader);

    // Program
    const program = gl.createProgram();
    if (!program) return;
    gl.attachShader(program, vertexShader);
    gl.attachShader(program, fragmentShader);
    gl.linkProgram(program);
    gl.useProgram(program);
    programRef.current = program;

    // Create buffer
    const positions = new Float32Array([-1, -1, 1, -1, -1, 1, 1, 1]);
    const buffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, buffer);
    gl.bufferData(gl.ARRAY_BUFFER, positions, gl.STATIC_DRAW);

    const positionLoc = gl.getAttribLocation(program, "position");
    gl.enableVertexAttribArray(positionLoc);
    gl.vertexAttribPointer(positionLoc, 2, gl.FLOAT, false, 0, 0);

    const timeLoc = gl.getUniformLocation(program, "time");
    const resolutionLoc = gl.getUniformLocation(program, "resolution");

    // Animation loop
    const animate = () => {
      timeRef.current += 0.016;

      gl.uniform1f(timeLoc, timeRef.current);
      gl.uniform2f(resolutionLoc, canvas.width, canvas.height);
      gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);

      animationIdRef.current = requestAnimationFrame(animate);
    };
    animate();

    return () => {
      if (animationIdRef.current) {
        cancelAnimationFrame(animationIdRef.current);
      }
      window.removeEventListener("resize", resizeCanvas);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 w-full h-full" />;
}
